package com.letotoo06.ideastormimport android.os.StrictModeimport android.util.Logimport com.google.gson.Gsonimport org.mindrot.jbcrypt.BCryptimport java.sql.Connectionimport java.sql.DriverManagerimport java.sql.SQLException// --- STRUCTURE DES DONNÉES DE SAUVEGARDE ---data class GameSaveData(    val score: Double,    val perClick: Double,    val perSecond: Double,    val rebirthCount: Int,    val hasDebile: Boolean,    val hasMimir: Boolean,    val hasPistolet: Boolean,    val hasSeducteur: Boolean,    val hasGoose: Boolean,    val upgradesCost: Map<String, Double>)object DatabaseManager {    // --- CONFIGURATION AIVEN ---    private const val DB_HOST = "DB_HOST"    private const val DB_PORT = "DB_PORT"    private const val DB_NAME = "DB"    private const val DB_USER = "USER"    private const val DB_PASS = "MET_ICI_LE_MDP"    // URL AVEC PARAMÈTRES DE COMPATIBILITÉ ANDROID + SSL AIVEN    private const val DB_URL = "jdbc:mysql://$DB_HOST:$DB_PORT/$DB_NAME?" +            "user=$DB_USER&password=$DB_PASS" +            "&useSSL=true&verifyServerCertificate=false&allowPublicKeyRetrieval=true&serverTimezone=UTC"    private val gson = Gson()    init {        // Autorise les requêtes réseau sur le thread principal pour le prototype        val policy = StrictMode.ThreadPolicy.Builder().permitAll().build()        StrictMode.setThreadPolicy(policy)    }    private fun getConnection(): Connection? {        return try {            // Pour la version 5.1.49, le nom de la classe est différent :            Class.forName("com.mysql.jdbc.Driver")            DriverManager.getConnection(DB_URL)        } catch (e: Exception) {            Log.e("DATABASE_MANAGER", "Erreur : ${e.message}")            null        }    }    // --- INSCRIPTION AVEC HACHAGE BCRYPT ---    fun signup(username: String, passwordRaw: String): User? {        val conn = getConnection() ?: return null        return try {            // Création des tables si manquantes            conn.createStatement().execute("CREATE TABLE IF NOT EXISTS users (id INT AUTO_INCREMENT PRIMARY KEY, username VARCHAR(255) UNIQUE, password_hash VARCHAR(255))")            conn.createStatement().execute("CREATE TABLE IF NOT EXISTS game_state (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT, save_data JSON, score DOUBLE, rebirth_count INT)")            // Hachage du mot de passe            val hashedPassword = BCrypt.hashpw(passwordRaw, BCrypt.gensalt())            val stmt = conn.prepareStatement(                "INSERT INTO users (username, password_hash) VALUES (?, ?)",                java.sql.Statement.RETURN_GENERATED_KEYS            )            stmt.setString(1, username)            stmt.setString(2, hashedPassword)            stmt.executeUpdate()            val rs = stmt.generatedKeys            if (rs.next()) {                val newId = rs.getInt(1)                // État de jeu initial                val stmtGame = conn.prepareStatement("INSERT INTO game_state (user_id, save_data, score, rebirth_count) VALUES (?, '{}', 0, 0)")                stmtGame.setInt(1, newId)                stmtGame.executeUpdate()                User(newId, username)            } else null        } catch (e: SQLException) {            Log.e("DATABASE_MANAGER", "Erreur Signup : ${e.message}")            null        } finally {            conn.close()        }    }    // --- CONNEXION AVEC VÉRIFICATION BCRYPT ---    fun login(username: String, passwordRaw: String): User? {        val conn = getConnection() ?: return null        return try {            val stmt = conn.prepareStatement("SELECT id, username, password_hash FROM users WHERE username = ?")            stmt.setString(1, username)            val rs = stmt.executeQuery()            if (rs.next()) {                val storedHash = rs.getString("password_hash")                // On vérifie si le mot de passe brut correspond au hachage stocké                if (BCrypt.checkpw(passwordRaw, storedHash)) {                    User(rs.getInt("id"), rs.getString("username"))                } else {                    Log.w("DATABASE_MANAGER", "Mot de passe incorrect")                    null                }            } else {                Log.w("DATABASE_MANAGER", "Utilisateur non trouvé")                null            }        } catch (e: Exception) {            Log.e("DATABASE_MANAGER", "Erreur Login : ${e.message}")            null        } finally {            conn.close()        }    }    // --- SAUVEGARDE DU JEU ---    fun saveGame(userId: Int, score: Double, rebirthCount: Int, saveData: GameSaveData): Boolean {        val conn = getConnection() ?: return false        return try {            val json = gson.toJson(saveData)            val checkStmt = conn.prepareStatement("SELECT id FROM game_state WHERE user_id = ?")            checkStmt.setInt(1, userId)            val rs = checkStmt.executeQuery()            if (rs.next()) {                val stmt = conn.prepareStatement("UPDATE game_state SET save_data = ?, score = ?, rebirth_count = ? WHERE user_id = ?")                stmt.setString(1, json)                stmt.setDouble(2, score)                stmt.setInt(3, rebirthCount)                stmt.setInt(4, userId)                stmt.executeUpdate()            } else {                val stmt = conn.prepareStatement("INSERT INTO game_state (user_id, save_data, score, rebirth_count) VALUES (?, ?, ?, ?)")                stmt.setInt(1, userId)                stmt.setString(2, json)                stmt.setDouble(3, score)                stmt.setInt(4, rebirthCount)                stmt.executeUpdate()            }            true        } catch (e: Exception) {            Log.e("DATABASE_MANAGER", "Erreur SaveGame : ${e.message}")            false        } finally {            conn.close()        }    }    // --- CHARGEMENT DU JEU ---    fun loadGame(userId: Int): GameSaveData? {        val conn = getConnection() ?: return null        return try {            val stmt = conn.prepareStatement("SELECT save_data FROM game_state WHERE user_id = ?")            stmt.setInt(1, userId)            val rs = stmt.executeQuery()            if (rs.next()) {                val json = rs.getString("save_data")                if (json != null && json.length > 2) {                    gson.fromJson(json, GameSaveData::class.java)                } else null            } else null        } catch (e: Exception) {            Log.e("DATABASE_MANAGER", "Erreur LoadGame : ${e.message}")            null        } finally {            conn.close()        }    }}